#!/usr/bin/env python3
"""Regenerate the auto-generated subtrees of docs/reference/.

ADR-0001 Phase 15. Three canonical sources fan out into the docs site:

  contracts/api/openapi.yaml   -> docs/reference/api/<tag>.md     (per-tag groupings)
                                  docs/reference/api/index.md     (TOC)
  [project.scripts]            -> docs/reference/cli/<name>.md    (one per console-script)
                                  docs/reference/cli/index.md     (TOC)
  contracts/services/*.yaml    -> docs/reference/services.md      (single rollup)

Idempotency contract:
  Re-running the script on an unchanged source tree MUST produce
  byte-identical output. Tests can verify this by checking
  `git status docs/reference/` after a fresh run.

Console-script: this isn't pinned to [project.scripts] yet (it lives
under bin/ops/ per the Phase 8 ops-tooling convention). Invoke via
`python3 bin/ops/generate_reference_docs.py` or the wrapper
`bash bin/ops/generate-reference-docs.sh`.
"""

from __future__ import annotations

import json
import re
import subprocess
import sys
import tomllib
from collections import defaultdict
from pathlib import Path
from typing import Any

import yaml

REPO_ROOT = Path(__file__).resolve().parents[2]
OPENAPI_YAML = REPO_ROOT / "contracts" / "api" / "openapi.yaml"
PYPROJECT = REPO_ROOT / "pyproject.toml"
SERVICES_DIR = REPO_ROOT / "contracts" / "services"
DOCS_REFERENCE = REPO_ROOT / "docs" / "reference"
DOCS_API = DOCS_REFERENCE / "api"
DOCS_CLI = DOCS_REFERENCE / "cli"

AUTO_GEN_BANNER = (
    "<!-- AUTO-GENERATED by bin/ops/generate_reference_docs.py."
    " DO NOT EDIT BY HAND. -->"
)


# --------------------------------------------------------------------------
# Helpers
# --------------------------------------------------------------------------


def _slug(s: str) -> str:
    """Filesystem-safe slug for a tag or script name."""
    return re.sub(r"[^a-z0-9]+", "-", s.lower()).strip("-") or "untitled"


def _write(path: Path, content: str) -> bool:
    """Write `content` to `path` only if it differs. Returns True if changed."""
    path.parent.mkdir(parents=True, exist_ok=True)
    if path.exists() and path.read_text(encoding="utf-8") == content:
        return False
    path.write_text(content, encoding="utf-8")
    return True


def _clear_generated(directory: Path, keep: set[str]) -> int:
    """Remove auto-generated *.md from `directory` except names in `keep`.

    Stale files are detected by the AUTO_GEN_BANNER on the first non-blank
    line — we never blow away a hand-authored page that ended up in the
    same dir.
    """
    if not directory.exists():
        return 0
    removed = 0
    for f in directory.glob("*.md"):
        if f.name in keep:
            continue
        head = f.read_text(encoding="utf-8").splitlines()[:1]
        if head and head[0].startswith("<!-- AUTO-GENERATED by"):
            f.unlink()
            removed += 1
    return removed


# --------------------------------------------------------------------------
# OpenAPI -> docs/reference/api/<tag>.md + index.md
# --------------------------------------------------------------------------


def _load_openapi() -> dict[str, Any]:
    raw = OPENAPI_YAML.read_text(encoding="utf-8")
    data = yaml.safe_load(raw) or {}
    if not isinstance(data, dict):
        raise SystemExit(f"unexpected openapi.yaml shape: {type(data).__name__}")
    return data


def _operations_by_tag(spec: dict[str, Any]) -> dict[str, list[dict[str, Any]]]:
    """Group every (path, method, operation) by its first tag.

    Operations missing a `tags` field land in an `Untagged` bucket.
    """
    grouped: dict[str, list[dict[str, Any]]] = defaultdict(list)
    methods = {"get", "post", "put", "patch", "delete", "head", "options"}
    for path, item in (spec.get("paths") or {}).items():
        if not isinstance(item, dict):
            continue
        for method, op in item.items():
            if method.lower() not in methods or not isinstance(op, dict):
                continue
            tags = op.get("tags") or ["Untagged"]
            tag = tags[0] if tags else "Untagged"
            grouped[tag].append(
                {
                    "path": path,
                    "method": method.upper(),
                    "summary": op.get("summary") or op.get("operationId") or "",
                    "description": (op.get("description") or "").strip(),
                    "operationId": op.get("operationId") or "",
                }
            )
    # stable: sort each tag's ops by path then method
    for ops in grouped.values():
        ops.sort(key=lambda o: (o["path"], o["method"]))
    return grouped


def _render_api_tag_page(
    tag: str,
    tag_description: str,
    operations: list[dict[str, Any]],
) -> str:
    lines: list[str] = [
        AUTO_GEN_BANNER,
        f"<!-- Source: contracts/api/openapi.yaml (tag={tag}). -->",
        "",
        f"# {tag} API",
        "",
    ]
    if tag_description:
        lines.append(tag_description)
        lines.append("")
    lines.append(
        "Source of truth: [`contracts/api/openapi.yaml`]"
        "(../../../contracts/api/openapi.yaml). "
        "Edit the OpenAPI spec, then re-run "
        "`bash bin/ops/generate-reference-docs.sh`."
    )
    lines.append("")
    lines.append("## Operations")
    lines.append("")
    lines.append("| Method | Path | Summary |")
    lines.append("|--------|------|---------|")
    for op in operations:
        summary = op["summary"].split("\n", 1)[0].strip() or "&mdash;"
        # Pipe-escape inside markdown table cells.
        summary = summary.replace("|", "\\|")
        path_cell = f"`{op['path']}`"
        lines.append(f"| `{op['method']}` | {path_cell} | {summary} |")
    lines.append("")
    return "\n".join(lines) + "\n"


def _render_api_index(by_tag: dict[str, list[dict[str, Any]]],
                     tag_descriptions: dict[str, str]) -> str:
    lines = [
        AUTO_GEN_BANNER,
        "<!-- Source: contracts/api/openapi.yaml. -->",
        "",
        "# API Reference",
        "",
        "REST endpoints exposed by the Media Stack Controller, grouped by"
        " OpenAPI tag. Each page is rendered from the operation list in"
        " [`contracts/api/openapi.yaml`](../../../contracts/api/openapi.yaml).",
        "",
        "## Tag index",
        "",
        "| Tag | Operations | Summary |",
        "|-----|-----------:|---------|",
    ]
    for tag in sorted(by_tag):
        slug = _slug(tag)
        count = len(by_tag[tag])
        desc = tag_descriptions.get(tag, "").split("\n", 1)[0].strip()
        desc = desc.replace("|", "\\|") or "&mdash;"
        lines.append(f"| [{tag}]({slug}.md) | {count} | {desc} |")
    lines.append("")
    return "\n".join(lines) + "\n"


def regenerate_api_docs() -> tuple[int, int]:
    """Returns (pages_written, pages_unchanged)."""
    spec = _load_openapi()
    grouped = _operations_by_tag(spec)
    tag_descriptions = {
        t.get("name"): (t.get("description") or "").strip()
        for t in (spec.get("tags") or [])
        if isinstance(t, dict) and t.get("name")
    }

    DOCS_API.mkdir(parents=True, exist_ok=True)
    written = 0
    unchanged = 0

    expected_files: set[str] = {"index.md"}
    for tag, ops in grouped.items():
        slug = _slug(tag)
        fname = f"{slug}.md"
        expected_files.add(fname)
        page = _render_api_tag_page(tag, tag_descriptions.get(tag, ""), ops)
        if _write(DOCS_API / fname, page):
            written += 1
        else:
            unchanged += 1

    index = _render_api_index(grouped, tag_descriptions)
    if _write(DOCS_API / "index.md", index):
        written += 1
    else:
        unchanged += 1

    # Drop stale auto-generated files that no longer match a tag.
    _clear_generated(DOCS_API, keep=expected_files)
    return written, unchanged


# --------------------------------------------------------------------------
# [project.scripts] -> docs/reference/cli/<name>.md + index.md
# --------------------------------------------------------------------------


def _load_console_scripts() -> dict[str, str]:
    """Returns {script_name: 'module:attr'} from pyproject.toml."""
    with PYPROJECT.open("rb") as fh:
        data = tomllib.load(fh)
    scripts = (data.get("project") or {}).get("scripts") or {}
    if not isinstance(scripts, dict):
        return {}
    return {str(k): str(v) for k, v in scripts.items()}


def _capture_help(script: str, target: str) -> tuple[str, bool]:
    """Run `<script> --help` (preferring the binary if present, else
    `python -m <module>`). Returns (text, ok).

    ok=False captures the failure message verbatim so docs reflect the
    real state of a CLI that's broken at the moment.
    """
    binary = REPO_ROOT / ".venv-smoke" / "bin" / script
    cmd: list[str]
    if binary.exists():
        cmd = [str(binary), "--help"]
    else:
        # Fall back to running the module directly. Some console-scripts
        # call sys.exit unconditionally on --help; capture stdout+stderr.
        module = target.split(":", 1)[0]
        cmd = [sys.executable, "-m", module, "--help"]
    try:
        proc = subprocess.run(
            cmd,
            cwd=REPO_ROOT,
            capture_output=True,
            text=True,
            timeout=20,
            check=False,
        )
    except (FileNotFoundError, subprocess.TimeoutExpired) as exc:
        return f"<help unavailable: {type(exc).__name__}: {exc}>", False
    out = (proc.stdout or "") + (proc.stderr or "")
    out = out.strip() or "<no output>"
    return out, proc.returncode == 0


def _render_cli_page(script: str, target: str, help_text: str, ok: bool) -> str:
    status = "captured live" if ok else "stale (CLI exited non-zero)"
    lines = [
        AUTO_GEN_BANNER,
        f"<!-- Source: pyproject.toml [project.scripts] {script} = \"{target}\". -->",
        "",
        f"# `{script}`",
        "",
        f"Console-script entry point declared in"
        f" [`pyproject.toml`](../../../pyproject.toml)"
        f" as `{script} = \"{target}\"`.",
        "",
        f"Help output ({status}):",
        "",
        "```text",
        help_text,
        "```",
        "",
    ]
    return "\n".join(lines) + "\n"


def _render_cli_index(scripts: dict[str, str]) -> str:
    lines = [
        AUTO_GEN_BANNER,
        "<!-- Source: pyproject.toml [project.scripts]. -->",
        "",
        "# CLI Reference",
        "",
        "Every operator-facing console-script declared in"
        " [`pyproject.toml`](../../../pyproject.toml)"
        " under `[project.scripts]`. After `pip install -e .` each name"
        " resolves to a binary on `$PATH`.",
        "",
        "| Script | Module entry-point |",
        "|--------|--------------------|",
    ]
    for name in sorted(scripts):
        target = scripts[name]
        lines.append(f"| [`{name}`]({_slug(name)}.md) | `{target}` |")
    lines.append("")
    return "\n".join(lines) + "\n"


def regenerate_cli_docs() -> tuple[int, int]:
    scripts = _load_console_scripts()
    if not scripts:
        print("warn: no [project.scripts] entries found in pyproject.toml",
              file=sys.stderr)

    DOCS_CLI.mkdir(parents=True, exist_ok=True)
    written = 0
    unchanged = 0
    expected: set[str] = {"index.md"}
    for name, target in sorted(scripts.items()):
        slug = _slug(name)
        fname = f"{slug}.md"
        expected.add(fname)
        help_text, ok = _capture_help(name, target)
        page = _render_cli_page(name, target, help_text, ok)
        if _write(DOCS_CLI / fname, page):
            written += 1
        else:
            unchanged += 1

    index = _render_cli_index(scripts)
    if _write(DOCS_CLI / "index.md", index):
        written += 1
    else:
        unchanged += 1

    _clear_generated(DOCS_CLI, keep=expected)
    return written, unchanged


# --------------------------------------------------------------------------
# contracts/services/*.yaml -> docs/reference/services.md
# --------------------------------------------------------------------------


def _load_services() -> list[dict[str, Any]]:
    services: list[dict[str, Any]] = []
    for f in sorted(SERVICES_DIR.glob("*.yaml")):
        if f.name.startswith("_"):
            continue
        try:
            data = yaml.safe_load(f.read_text(encoding="utf-8")) or {}
        except yaml.YAMLError as exc:
            print(f"warn: skipping {f.name}: {exc}", file=sys.stderr)
            continue
        svc = data.get("service") if isinstance(data, dict) else None
        if not isinstance(svc, dict):
            continue
        services.append(
            {
                "file": f.name,
                "id": svc.get("id") or f.stem,
                "name": svc.get("name") or svc.get("id") or f.stem,
                "desc": (svc.get("desc") or "").strip(),
                "category": svc.get("category") or "",
                "host": svc.get("host") or "",
                "port": svc.get("port"),
                "health_path": svc.get("health_path") or "",
            }
        )
    return services


def regenerate_services_doc() -> bool:
    services = _load_services()
    by_category: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for svc in services:
        by_category[svc["category"] or "uncategorized"].append(svc)

    lines = [
        AUTO_GEN_BANNER,
        "<!-- Source: contracts/services/*.yaml. -->",
        "",
        "# Services Catalog (auto-generated)",
        "",
        "Per-service summary derived from the YAML contracts in"
        " [`contracts/services/`](../../contracts/services/)."
        " Each row points back to its source file — edit there and"
        " re-run `bash bin/ops/generate-reference-docs.sh` to refresh"
        " this page.",
        "",
        f"Total services: **{len(services)}** across"
        f" {len(by_category)} categories.",
        "",
    ]
    for category in sorted(by_category):
        lines.append(f"## {category}")
        lines.append("")
        lines.append("| Service | Host | Port | Health | Description | Source |")
        lines.append("|---------|------|-----:|--------|-------------|--------|")
        for svc in sorted(by_category[category], key=lambda s: s["id"]):
            port = svc["port"] if svc["port"] not in (None, "") else "&mdash;"
            health = f"`{svc['health_path']}`" if svc["health_path"] else "&mdash;"
            desc = (svc["desc"] or "").replace("|", "\\|") or "&mdash;"
            host = f"`{svc['host']}`" if svc["host"] else "&mdash;"
            src = (
                f"[`{svc['file']}`]"
                f"(../../contracts/services/{svc['file']})"
            )
            lines.append(
                f"| **{svc['name']}** (`{svc['id']}`) | {host} | {port} |"
                f" {health} | {desc} | {src} |"
            )
        lines.append("")

    out = "\n".join(lines) + "\n"
    return _write(DOCS_REFERENCE / "services.md", out)


# --------------------------------------------------------------------------
# main
# --------------------------------------------------------------------------


def main(argv: list[str] | None = None) -> int:
    argv = argv if argv is not None else sys.argv[1:]
    quiet = "--quiet" in argv or "-q" in argv
    log = (lambda *a, **k: None) if quiet else print  # noqa: E731

    log("[1/3] OpenAPI -> docs/reference/api/")
    api_written, api_unchanged = regenerate_api_docs()
    log(f"      {api_written} written, {api_unchanged} unchanged")

    log("[2/3] [project.scripts] -> docs/reference/cli/")
    cli_written, cli_unchanged = regenerate_cli_docs()
    log(f"      {cli_written} written, {cli_unchanged} unchanged")

    log("[3/3] contracts/services/*.yaml -> docs/reference/services.md")
    services_changed = regenerate_services_doc()
    log(f"      {'written' if services_changed else 'unchanged'}")

    summary = {
        "api": {"written": api_written, "unchanged": api_unchanged},
        "cli": {"written": cli_written, "unchanged": cli_unchanged},
        "services": {"changed": services_changed},
    }
    if "--json" in argv:
        print(json.dumps(summary, indent=2, sort_keys=True))
    return 0


if __name__ == "__main__":
    sys.exit(main())
